package com.example.bankingapp;

import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;

import java.text.NumberFormat;
import java.util.Locale;

public class BankingActivity extends AppCompatActivity {

    private double accountBalance = 1000.00; // example starting balance
    private TextView balanceTextView;
    private Button transactionButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);

        balanceTextView = findViewById(R.id.balanceTextView);
        transactionButton = findViewById(R.id.transactionButton);

        updateBalanceDisplay();

        transactionButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction(-100); // Example transaction: withdrawing 100
                updateBalanceDisplay();
            }
        });
    }

    private void processTransaction(double amount) {
        // Simple transaction logic
        if (accountBalance + amount >= 0) {
            accountBalance += amount;
            Toast.makeText(this, "Transaction successful", Toast.LENGTH_SHORT).show();
        } else {
            Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show();
        }
    }

    private void updateBalanceDisplay() {
        String formattedBalance = NumberFormat.getCurrencyInstance(new Locale("en", "US")).format(accountBalance);
        balanceTextView.setText("Balance: " + formattedBalance);
    }
}

